// app/actions.ts
'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export type CreatePostState = {
  error?: string;
  success?: boolean;
};

export async function createPost(
  prevState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title')?.toString().trim();
  const content = formData.get('content')?.toString().trim();

  // --- Validation ---
  if (!title) {
    return { error: 'Title is required.' };
  }
  if (title.length > 100) {
    return { error: 'Title must be under 100 characters.' };
  }
  if (!content) {
    return { error: 'Content is required.' };
  }

  // --- Create the post ---
  addPost({
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString(),
  });

  // --- Invalidate the "posts" cache tag ---
  // In Next.js 16, revalidateTag takes an optional second argument that
  // controls the cache lifecycle. Passing { expire: 0 } ensures the cached
  // entry expires immediately, so the next server render blocks on fresh data
  // rather than serving stale content.
  revalidateTag('posts', { expire: 0 });

  // --- Redirect to the posts list ---
  // Using redirect() here causes a full server-side render of /posts after
  // cache invalidation, so the user always sees the brand-new post immediately.
  redirect('/posts');
}


